// Lecture integrale article - screening approfondi sur PDF complet
// FULLTEXT_SCREENING_v1 (v0.2.6)
const PROXY = 'http://host.docker.internal:3456';
const items = $input.all();
const articles = items.map(i => i.json);
const question = (articles[0] && articles[0].question) || '';
const criteria = (articles[0] && articles[0].criteria) || '';

console.log('[Fulltext Screening] ' + articles.length + ' articles candidats');

const results = [];
const stats = { total: articles.length, eligible: 0, confirmed: 0, revised: 0, no_pdf: 0, no_decision: 0, extract_failed: 0 };

for (let i = 0; i < articles.length; i++) {
  const article = articles[i];
  const orig_decision = article.screening_decision || '';
  const pdf_path = article.pdf_local || '';

  // FULLTEXT_ELIGIBILITY_v2 : on analyse tout SAUF les Exclude deja decides
  // (permet le screening direct depuis dossier de PDFs sans pre-screening)
  if (orig_decision === 'Exclude') {
    results.push({ json: Object.assign({}, article, {
      _fulltext_skipped: 'already excluded by pre-screening'
    })});
    continue;
  }

  if (!pdf_path) {
    stats.no_pdf++;
    results.push({ json: Object.assign({}, article, {
      screening_decision_fulltext: orig_decision,
      screening_reason_fulltext: 'PDF non disponible - decision initiale conservee',
      screening_decision_initial: orig_decision,
      _fulltext_status: 'no_pdf'
    })});
    continue;
  }

  stats.eligible++;

  // === 1. Extract PDF text ===
  let full_text = '';
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: PROXY + '/extract-pdf',
      body: JSON.stringify({ pdf_path: pdf_path, max_chars: 30000, skip_biblio: true }),
      headers: { 'Content-Type': 'application/json' },
      json: true,
      timeout: 60000
    });
    if (resp && resp.success && resp.text) {
      full_text = resp.text.substring(0, 25000);
    } else {
      throw new Error((resp && resp.error) || 'PDF extraction failed');
    }
  } catch (e) {
    stats.extract_failed++;
    results.push({ json: Object.assign({}, article, {
      screening_decision_fulltext: orig_decision,
      screening_reason_fulltext: 'PDF extraction failed: ' + (e.message || e),
      screening_decision_initial: orig_decision,
      _fulltext_status: 'extract_failed'
    })});
    continue;
  }

    // FULLTEXT_METADATA_ENRICH_v3 - extraction automatique DOI + annee depuis le PDF
    if (!article.doi && full_text) {
      const doiMatch = full_text.substring(0, 8000).match(/\b10\.\d{4,9}\/[-._;()/:A-Z0-9]+/i);
      if (doiMatch) {
        // Nettoie la fin du DOI (point final, virgule, parenthese, etc.)
        article.doi = doiMatch[0].replace(/[.,;)\]]+$/, '');
      }
    }
    if (!article.year && full_text) {
      // Cherche annee en contexte editorial dans les premiers 6000 chars
      const ctxMatch = full_text.substring(0, 6000).match(/(?:received|accepted|published|copyright|year|date|\bPublished:?\b|©)\s*[:\-]?\s*.{0,40}?(19\d{2}|20[0-3]\d)/i);
      if (ctxMatch) {
        article.year = ctxMatch[1];
      } else {
        // Fallback : premiere annee plausible dans les 3000 premiers chars
        const yMatch = full_text.substring(0, 3000).match(/\b(19\d{2}|20[0-3]\d)\b/);
        if (yMatch) article.year = yMatch[1];
      }
    }
    // Nettoyer le titre : espaces multiples -> simple (utile pour les titres
    // generes depuis nom de fichier qui contiennent souvent '   ')
    if (article.title) {
      article.title = article.title.replace(/\s+/g, ' ').trim();
    }

  // FULLTEXT_CROSSREF_ENRICH_v1 - completer authors/journal/annee/abstract via Crossref par DOI
  if (article.doi && (!article.authors || article.authors.length === 0 || !article.journal || !article.abstract)) {
    try {
      const _crUrl = 'https://api.crossref.org/works/' + encodeURIComponent(article.doi);
      const _cr = await this.helpers.httpRequest({
        method: 'GET',
        url: PROXY + '?url=' + encodeURIComponent(_crUrl),
        json: true,
        timeout: 20000
      });
      const _m = _cr && _cr.message;
      if (_m) {
        const _crTitle = (Array.isArray(_m.title) && _m.title[0]) ? _m.title[0] : '';
        // Filet anti-mauvais-DOI : recoupement du titre courant vs Crossref
        function _toks(t){ return (t||'').toLowerCase().replace(/[^a-z0-9 ]/g,' ').split(/\s+/).filter(function(w){ return w.length > 3; }); }
        const _a = _toks(article.title), _b = _toks(_crTitle);
        let _match = 0;
        for (let _k = 0; _k < _a.length; _k++) { if (_b.indexOf(_a[_k]) >= 0) _match++; }
        const _ratio = _b.length ? (_match / Math.min(_a.length || 1, _b.length)) : 0;
        const _trust = (!article.title) || (_a.length === 0) || (_ratio >= 0.34);
        if (_trust) {
          if ((!article.authors || article.authors.length === 0) && Array.isArray(_m.author)) {
            article.authors = _m.author.map(function(au){ return [au.given, au.family].filter(Boolean).join(' ') || au.name || ''; }).filter(Boolean);
          }
          if (!article.journal && Array.isArray(_m['container-title']) && _m['container-title'].length) {
            article.journal = _m['container-title'][0];
          }
          if (_crTitle) { article.title = _crTitle; }
          const _dp = (_m.issued && _m.issued['date-parts']) || (_m.published && _m.published['date-parts']) || null;
          if (_dp && _dp[0] && _dp[0][0]) { article.year = String(_dp[0][0]); }
          if (!article.abstract && _m.abstract) {
            article.abstract = _m.abstract.replace(/<[^>]+>/g, ' ').replace(/\s+/g, ' ').trim();
          }
          article._crossref_enriched = true;
        } else {
          article._crossref_status = 'doi_title_mismatch';
          console.log('[Fulltext Crossref] DOI/titre incoherent, enrich ignore: ' + article.doi);
        }
      }
    } catch (_e) {
      console.log('[Fulltext Crossref] enrich failed for ' + article.doi + ': ' + (_e.message || _e));
    }
  }

  // === 2. Build prompt + Call LLM ===
  const title = (article.title || '').substring(0, 200);
  const prompt =
    'You are a systematic review screener performing in-depth full-text analysis.\n\n' +
    'RESEARCH QUESTION:\n' + question.substring(0, 500) + '\n\n' +
    'INCLUSION/EXCLUSION CRITERIA:\n' + criteria.substring(0, 500) + '\n\n' +
    '=== ARTICLE FULL TEXT ===\n' +
    'TITLE: ' + title + '\n\n' +
    'FULL TEXT (truncated to first 25000 chars, bibliography removed):\n' + full_text + '\n\n' +
    '=== INITIAL DECISION (abstract-only pre-screening) ===\n' +
    orig_decision + '\n\n' +
    '=== YOUR TASK ===\n' +
    'Reconsider the decision based on the FULL TEXT (not just the abstract). ' +
    'You may confirm or change the initial decision. Output EXACTLY 2 lines:\n' +
    'Decision: <Include|Maybe|Exclude>\n' +
    'Reason: <one short sentence based on what you read in the full text>\n\n' +
    'Put Reason on the line directly after Decision (no blank line). ' +
    'No markdown. No explanation before or after. Start IMMEDIATELY with "Decision:".';

  try {
    const ollamaResp = await this.helpers.httpRequest({
      method: 'POST',
      url: PROXY + '/api/generate',
      body: JSON.stringify({
        model: 'qwen2.5:3b',
        prompt: prompt,
        stream: false,
        options: {
          temperature: 0,
          num_predict: 800,
          num_ctx: 32768,
          stop: ['\n\n\n', 'Article ', 'TITLE:', 'Article:']
        },
        keep_alive: '30m',
        _ultralab_task: 'chat'
      }),
      headers: { 'Content-Type': 'application/json' },
      json: true,
      timeout: 900000
    });
    const raw = (ollamaResp && ollamaResp.response) || '';
    const decMatch = raw.match(/decision[\s:=]+(include|maybe|exclude)/i);
    let new_decision = orig_decision;
    let new_reason = '';
    if (decMatch) {
      const w = decMatch[1].toLowerCase();
      new_decision = w.indexOf('inc') === 0 ? 'Include' : (w.indexOf('exc') === 0 ? 'Exclude' : 'Maybe');
      const reasonMatch = raw.match(/reason[\s:=]+([\s\S]{0,400})/i);
      if (reasonMatch) {
        new_reason = reasonMatch[1].split(/\n\n|\r\n\r\n/)[0].trim().substring(0, 300);
      }
    } else {
      stats.no_decision++;
      new_reason = 'LLM did not return parseable decision - kept initial decision [raw: ' + raw.substring(0, 150).replace(/\s+/g, ' ') + ']';
    }
    // Securite : si pas de reason et qu'on a une decision, marquer
    if (!new_reason && decMatch) {
      new_reason = '(no reason returned)';
    }
    // Securite scientifique : Include sans reason -> Maybe (cf v0.2.5 #37)
    if (new_decision === 'Include' && (!new_reason || /^\(no reason/i.test(new_reason))) {
      new_decision = 'Maybe';
      new_reason = 'LLM a propose Include mais sans justification verifiable - reclasse Maybe pour verification manuelle';
    }
    if (new_decision === orig_decision) stats.confirmed++; else stats.revised++;
    results.push({ json: Object.assign({}, article, {
      screening_decision_fulltext: new_decision,
      screening_reason_fulltext: new_reason,
      screening_decision_initial: orig_decision,
      _fulltext_status: new_decision === orig_decision ? 'confirmed' : 'revised',
      _fulltext_raw_preview: raw.substring(0, 250).replace(/\s+/g, ' ')
    })});
  } catch (e) {
    stats.no_decision++;
    results.push({ json: Object.assign({}, article, {
      screening_decision_fulltext: orig_decision,
      screening_reason_fulltext: 'LLM call error: ' + (e.message || e),
      screening_decision_initial: orig_decision,
      _fulltext_status: 'llm_error'
    })});
  }
}

console.log('[Fulltext Screening] Stats: ' + JSON.stringify(stats));

return results;
